package com.socialblog.interaction.api;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.repository.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.test.web.servlet.MockMvc;import java.util.UUID;import static org.assertj.core.api.Assertions.assertThat;import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.jwt;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc class InteractionControllerIntegrationTest{@Autowired MockMvc mvc;@Autowired TargetProjectionRepository targets;@Autowired OutboxEventRepository outbox;@Test void likeUnlikeAreIdempotentAndExposeCount()throws Exception{UUID target=UUID.randomUUID(),actor=UUID.randomUUID();targets.save(new TargetProjection(new TargetKey(TargetType.ARTICLE,target),true));String path="/api/v1/interactions/ARTICLE/"+target+"/like";mvc.perform(put(path).header("X-Correlation-ID","like-correlation").with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(1)).andExpect(jsonPath("$.likedByCurrentUser").value(true));mvc.perform(put(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(1));assertThat(outbox.findAll().stream().filter(e->e.getPayload().contains("InteractionCreated")).count()).isEqualTo(1);assertThat(outbox.findAll()).anySatisfy(e->assertThat(e.getPayload()).contains("like-correlation"));mvc.perform(get("/api/v1/interactions/ARTICLE/"+target)).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(1)).andExpect(jsonPath("$.likedByCurrentUser").value(false));mvc.perform(delete(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(0));mvc.perform(delete(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(0));assertThat(outbox.findAll().stream().filter(e->e.getPayload().contains("InteractionRemoved")).count()).isEqualTo(1);}@Test void rejectsUnavailableTarget()throws Exception{mvc.perform(put("/api/v1/interactions/COMMENT/"+UUID.randomUUID()+"/like").with(jwt().jwt(j->j.subject(UUID.randomUUID().toString())))).andExpect(status().isConflict()).andExpect(jsonPath("$.code").value("TARGET_NOT_AVAILABLE"));}@Test void mutationRequiresAuthentication()throws Exception{mvc.perform(put("/api/v1/interactions/ARTICLE/"+UUID.randomUUID()+"/like")).andExpect(status().isUnauthorized());}@Test void standardizesTargetParameterErrors()throws Exception{mvc.perform(get("/api/v1/interactions/POST/"+UUID.randomUUID())).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_TARGET_TYPE")).andExpect(jsonPath("$.fields.type").isNotEmpty());mvc.perform(get("/api/v1/interactions/ARTICLE/not-a-uuid")).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_REQUEST_PARAMETER")).andExpect(jsonPath("$.fields.target").isNotEmpty());}}
